package base;import org.junit.jupiter.api.AfterEach;import org.junit.jupiter.api.BeforeEach;import org.openqa.selenium.WebDriver;import org.openqa.selenium.chrome.ChromeDriver;import org.openqa.selenium.chrome.ChromeOptions;import java.time.Duration;public class BaseTest {    protected WebDriver driver;    @BeforeEach    void setUp() {        ChromeOptions options = new ChromeOptions();        options.addArguments("--incognito");        options.addArguments("--disable-cache");        options.addArguments("--window-size=1920,1080");        if (System.getenv("GITHUB_ACTIONS") != null) {            options.addArguments("--headless=new");            options.addArguments("--no-sandbox");            options.addArguments("--disable-dev-shm-usage");        }        driver = new ChromeDriver(options);        driver.manage().timeouts().implicitlyWait(Duration.ofSeconds(3));        driver.manage().deleteAllCookies();        driver.manage().window().maximize();    }    @AfterEach    void tearDown() {        if (driver != null) {            driver.manage().deleteAllCookies();            driver.quit();        }    }}